// ─── Подготовка списков устройств для выбора в настройках ───────────────────
var tempSensorList  = getServiceList([HS.TemperatureSensor],  HC.CurrentTemperature);
var thermostatList  = getServiceList([HS.Thermostat],         HC.TargetHeatingCoolingState);
var occupancyList   = getServiceList([HS.OccupancySensor],    HC.OccupancyDetected);
var secSystemList   = getServiceList([HS.SecuritySystem],     HC.SecuritySystemCurrentState);
var switchList      = getServiceList([HS.Switch],             HC.On);
var contactList     = getServiceList([HS.ContactSensor],      HC.ContactSensorState);

info = {
