      value: "Спальня",
      formType: "list",
      values: [
        { name: { ru: "Спальня",  en: "Bedroom"     }, value: "Спальня"  },
        { name: { ru: "Гостиная", en: "Living room"  }, value: "Гостиная" },
        { name: { ru: "Детская",  en: "Kids room"    }, value: "Детская"  },
        { name: { ru: "Кабинет",  en: "Office"       }, value: "Кабинет"  },
        { name: { ru: "Другая",   en: "Other"         }, value: "Другая"   }
      ]
    },

    // ── Переключатель Зима / Лето ─────────────────────────────────────────
    winterSummerSwitch: {
      name: { ru: "Переключатель Зима/Лето (Switch)", en: "Winter/Summer switch" },
      desc: { ru: "ON=зима, логика выключена. OFF=лето, логика работает. Если не задан — считаем лето.", en: "ON=winter (off), OFF=summer (on). Empty=summer." },
      type: "String",
      value: "",
      formType: "list",
      values: switchList
