    // ── Сигнализация ────────────────────────────────────────────────────────
    securityService: {
      name: { ru: "Сигнализация / хаб СХ (режим дома)", en: "Security system (hub mode)" },
      desc: { ru: "0=Дома, 1=Не дома, 2=Ночь. При 'Не дома' кондиционер выключается. Если не задана — считаем Дома.", en: "0=Home, 1=Away, 2=Night. Empty=Home." },
      type: "String",
      value: "",
      formType: "list",
      values: secSystemList
