    tempService: {
      name: { ru: "Датчик температуры комнаты (TemperatureSensor)", en: "Room temperature sensor" },
      desc: { ru: "Внутренний датчик. Основной сигнал управления кондиционером.", en: "Room temperature sensor — main control signal." },
      type: "String",
      value: "",
      formType: "list",
      values: tempSensorList
