// ═══════════════════════════════════════════════════════════════════════════
// ТОЧКА ВХОДА
// ═══════════════════════════════════════════════════════════════════════════
function trigger() {
  // Используем arguments[] — безопасно даже если платформа передаёт меньше параметров
  var source    = arguments[0];
  var value     = arguments[1];
  var _vars     = (arguments[2] && typeof arguments[2] === "object") ? arguments[2] : {};
  var _opt      = (arguments[3] && typeof arguments[3] === "object") ? arguments[3] : {};
  try {
    if (_opt.logEnabled) {
      console.info("[Кондиционер] [DEBUG] trigger: source=" + source +
        " value=" + JSON.stringify(value));
    }

    // Определяем ручное управление по значению триггера:
    // Источник анализировать ненадёжно — формат меняется в зависимости от контекста.
    // Логика:
    //   value=0 и наш lastState=2 (мы считали что кондиционер работает) →
    //     кто-то внешний выключил → ставим manualOff=true
    //   value=0 и наш lastState=0 (мы сами выключили) → это наш собственный триггер → игнорируем
    //   value=2 и manualOff=true → ручное включение → снимаем блокировку
    //   value=2 и manualOff=false → MQTT-реверт или пользователь включил → обрабатывается в runLogic

    var triggerValue = (typeof value === "object" && value !== null) ? value.value : value;
    var srcStr = String(source || "");
    var isOurLogic = (srcStr.indexOf("LOGIC") >= 0);
    var isMQTT     = (srcStr.indexOf("CLINK") >= 0 || srcStr.indexOf("MQTT") >= 0);

    if (!isOurLogic) {
      var wantedWasOn = (_vars.lastState && _vars.lastState.mode === 2);

      if ((triggerValue === 0 || triggerValue === "0") && wantedWasOn && !isMQTT) {
        // Кто-то внешний (пользователь или другой сценарий) выключил пока мы думали что он работает
        if (_opt.logEnabled) console.info("[Кондиционер] [" + (_opt.room || "-") + "] Внешнее выключение — блокируем автовключение");
        _vars.manualOff = true;
        _vars.manualOffTs = Date.now();
        if (!_vars.lastState) _vars.lastState = { mode: 0, temp: 0, speed: 0 };
        else _vars.lastState.mode = 0;
      } else if (triggerValue === 2 || triggerValue === "2") {
        if (_vars.manualOff && !isMQTT) {
          if (_opt.logEnabled) console.info("[Кондиционер] [" + (_opt.room || "-") + "] Внешнее включение — снимаем блокировку");
          _vars.manualOff = false;
        }
      }
    }

    setupCron(_vars, _opt);
    runLogic(_vars, _opt);
  } catch (e) {
    console.error("[Кондиционер] trigger: " + e.message + (e.lineNumber ? " (line " + e.lineNumber + ")" : ""));
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// КРОН (каждую минуту)
// ═══════════════════════════════════════════════════════════════════════════
function setupCron(variables, options) {
  var same = (variables.prevNightStart === options.nightStart &&
              variables.prevNightEnd   === options.nightEnd);
  if (same && variables.checkCron) return;

  if (variables.checkCron) { variables.checkCron.clear(); variables.checkCron = undefined; }
  variables.prevNightStart = options.nightStart;
  variables.prevNightEnd   = options.nightEnd;

  variables.checkCron = Cron.schedule("0 * * * * *", function() {
    try { runLogic(variables, options); }
    catch(e) { console.error("[Кондиционер] [" + (options && options.room ? options.room : "?") + "] cron: " + e.message + (e.lineNumber ? " (line " + e.lineNumber + ")" : "")); }
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// ОСНОВНАЯ ЛОГИКА
// ═══════════════════════════════════════════════════════════════════════════
function runLogic(variables, options) {
  if (!options || typeof options.room === "undefined" && typeof options.acService === "undefined") {
    console.warn("[Кондиционер] runLogic: options не готов, пропускаем цикл");
    return;
  }
  var room = options.room || "?";

  // ── 1. Зима ────────────────────────────────────────────────────────────
  var winter = isWinterMode(options);
  if (logOnChange(variables, "lastWinter", winter, winter
        ? "[" + room + "] Зима — логика выключена"
        : "[" + room + "] Лето — логика включена", options)) {}
  if (winter) {
    turnOffAC(options, variables, "Зима: логика выключена");
    return;
  }

  // ── 2. Режим охраны ────────────────────────────────────────────────────
  var secState = getSecurityState(options.securityService);
  logOnChange(variables, "lastSecState", secState,
    secState === 1 ? "[" + room + "] Режим: Не дома — выключаем" :
    secState === 2 ? "[" + room + "] Режим: Ночь" :
                     "[" + room + "] Режим: Дома", options);
  if (secState === 1) {
    turnOffAC(options, variables, "Режим: Не дома");
    return;
  }

  var isNight = (secState === 2) || isNightTime(options);

  // ── 3. Окна ────────────────────────────────────────────────────────────
  var winOpen = checkWindowOpen(options, room, variables);
  if (winOpen) {
    turnOffAC(options, variables, "Окно открыто в комнате " + room);
    cancelOffTimer(variables);
    return;
  }

  // ── 4. Уличная температура ─────────────────────────────────────────────
  var outdoorOk = isOutdoorTempOk(options);
  logOnChange(variables, "lastOutdoorOk", outdoorOk,
    outdoorOk
      ? "[" + room + "] Уличная температура в норме"
      : "[" + room + "] Уличная температура ниже " + options.outdoorTempMin + "°C — выключаем", options);
  if (!outdoorOk) {
    turnOffAC(options, variables, "Уличная температура ниже " + options.outdoorTempMin + "°C");
    return;
  }

  // ── 5. Присутствие ─────────────────────────────────────────────────────
  var personAtHome = isPersonAtHome(options);
  logOnChange(variables, "lastPersonAtHome", personAtHome,
    personAtHome
      ? "[" + room + "] Кто-то дома"
      : "[" + room + "] Никого дома", options);
  if (!personAtHome) {
    scheduleOff(variables, options, "Никого дома");
    return;
  }

  var personInRoom = isPersonInRoom(options);

  logOnChange(variables, "lastPersonInRoom", personInRoom,
    personInRoom
      ? "[" + room + "] Присутствие в комнате есть"
      : "[" + room + "] Никого в комнате", options);

  if (!personInRoom) {
    var wantedOnNow = (variables.lastState && variables.lastState.mode === 2);
    if (wantedOnNow) {
      // Кондиционер работает — запускаем логику выключения
      if (options.offDelayEnabled) {
        scheduleOff(variables, options, "Никого в комнате");
      } else {
        turnOffAC(options, variables, "Никого в комнате (без задержки)");
      }
    }
    // Если кондиционер не работает — ничего не делаем, таймер не нужен
    return;
  }

  cancelOffTimer(variables);

  // ── 6. Температура и скорость ──────────────────────────────────────────
  var temp = readSensor(options.tempService, HC.CurrentTemperature);
  if (temp === null) {
    console.warn("[Кондиционер] [" + room + "] Датчик температуры недоступен или не задан");
    return;
  }

  if (isNight) {
    handleMode(temp, variables, options, true);
  } else {
    handleMode(temp, variables, options, false);
  }

  // ── 7. Дисплей ─────────────────────────────────────────────────────────
  updateDisplay(isNight, options, variables);
}

// ═══════════════════════════════════════════════════════════════════════════
// ЕДИНЫЙ ОБРАБОТЧИК РЕЖИМА (день/ночь)
// Скорость пересчитывается каждый раз на основе текущей температуры.
// Динамика добавляет boost (+1..+N) если температура не снижается,
// и сбрасывает boost при снижении ниже нижней границы текущей скорости.
// ═══════════════════════════════════════════════════════════════════════════
function handleMode(temp, variables, options, isNight) {
  var tOff = isNight ? options.tempOffNight : options.tempOff;
  var tOn  = isNight ? options.tempOnNight  : options.tempOn;
  var tgt  = isNight ? options.targetTempNight : options.targetTemp;
  var type = isNight ? "night" : "day";

  // Используем lastState как источник истины о желаемом состоянии.
  // getACState читает CurrentHeatingCoolingState — реальное физическое состояние устройства.
  var wantedOn = (variables.lastState && variables.lastState.mode === 2);
  var realState = getACState(options);

  // Проверка «тихого» включения:
  // Мы думаем что кондиционер работает (wantedOn=true),
  // но CurrentHeatingCoolingState=0 — устройство не приняло команду включения.
  // Сбрасываем lastState → wantedOn становится false → ниже handleMode
  // снова включит кондиционер если температура выше tOn.
  if (wantedOn && realState === 0) {
    if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Устройство не ответило на включение — сброс и повтор в этом цикле");
    variables.lastState = { mode: 0, temp: 0, speed: 0 };
    variables.dynState  = undefined;
    wantedOn = false;
    // Не выходим — продолжаем, handleMode включит снова если temp >= tOn
  }

  // Диагностика: логируем состояние каждую минуту
  if (options.logEnabled) {
    console.info("[Кондиционер] [DEBUG] [" + (options.room || "-") + "]" +
      " Т=" + temp + "°C" +
      " tOn=" + tOn + " tOff=" + tOff +
      " ACstate=" + realState + " wantedOn=" + wantedOn +
      " lastMode=" + (variables.lastState ? variables.lastState.mode : "нет") +
      (isNight ? " (ночь)" : " (день)"));
  }

  // Защита от MQTT-реверта: устройство само вернуло режим охлаждения после нашего выключения.
  // Реверт определяем так: wantedOn=false И температура <= tOff (реально незачем работать).
  // Если температура > tOff — кондиционер включён вручную или условия выполнены, принимаем.
  if (!wantedOn && realState === 2) {
    if (temp <= tOff || variables.manualOff) {
      // Реверт: температура ниже порога ИЛИ пользователь только что выключил вручную
      // → повторно выключаем устройство
      if (variables.manualOff) {
        if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] MQTT-реверт после ручного выключения — блокируем");
      } else {
        if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] MQTT-реверт при Т=" + temp +
          "°C <= " + tOff + "°C — повторное выключение");
      }
      var svcR = getService(options.acService);
      if (svcR) {
        try { svcR.getCharacteristic(HC.TargetHeatingCoolingState).setValue(0); } catch(e) {}
      }
      return;
    } else {
      // Температура выше порога и нет ручного выключения — принимаем состояние
      if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Внешнее включение при Т=" +
        temp + "°C — принимаем, обновляем lastState");
      if (!variables.lastState) variables.lastState = { mode: 2, temp: tgt, speed: 1 };
      else variables.lastState.mode = 2;
      wantedOn = true;
    }
  }

  // Выключаем если охладились до нижнего порога
  if (wantedOn && temp <= tOff) {
    turnOffAC(options, variables, "Т=" + temp + "°C <= выкл. порог " + tOff + "°C");
    return;
  }

  // Сброс флага ручного выключения:
  if (variables.manualOff) {
    var manualMinutes = (options.manualOffMinutes !== undefined && options.manualOffMinutes > 0)
      ? options.manualOffMinutes : 0;

    var shouldReset = false;
    if (manualMinutes > 0) {
      // Режим таймера: сбрасываем через N минут
      var elapsedMs = Date.now() - (variables.manualOffTs || 0);
      if (elapsedMs >= manualMinutes * 60 * 1000) {
        shouldReset = true;
        if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Пауза " + manualMinutes +
          " мин после ручного выключения истекла — возобновляем автоуправление");
      }
    } else {
      // Режим tOff: сбрасываем когда температура упала до порога выключения
      if (temp <= tOff) {
        shouldReset = true;
        if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Т=" + temp +
          "°C достигла порога выкл — сброс ручного выключения");
      }
    }

    if (!shouldReset) return; // всё ещё в паузе
    variables.manualOff = false;
    variables.manualOffTs = undefined;
  }

  // Включаем если температура достигла порога включения
  // Регулируем скорость если кондиционер УЖЕ работает (wantedOn=true)
  if (temp >= tOn || wantedOn) {
    // Базовая скорость по текущей температуре (пересчёт каждый цикл)
    var baseSpeed = calcSpeed(temp, options, isNight);

    // Динамика: может добавить boost или сбросить его
    var finalSpeed = applyDynamic(baseSpeed, temp, type, variables, options);

    options._lastTemp = temp;
    debugLog(options, variables, temp, baseSpeed, finalSpeed, isNight, tOn, tOff);
    applyAC(options, 2, tgt, finalSpeed, variables);


  }
}

// ═══════════════════════════════════════════════════════════════════════════
// РАСЧЁТ БАЗОВОЙ СКОРОСТИ ПО ТЕКУЩЕЙ ТЕМПЕРАТУРЕ (5 ступеней)
// Всегда пересчитывается от реальной температуры прямо сейчас.
// 1=тихо 2=медленно 3=средне 4=быстро 5=турбо
// ═══════════════════════════════════════════════════════════════════════════
function debugLog(options, variables, temp, baseSpeed, finalSpeed, isNight, tOn, tOff) {
  if (!options.logEnabled) return;
  var t1 = isNight ? options.speedTemp1Night : options.speedTemp1;
  var t2 = isNight ? options.speedTemp2Night : options.speedTemp2;
  var t3 = isNight ? options.speedTemp3Night : options.speedTemp3;
  var t4 = isNight ? options.speedTemp4Night : options.speedTemp4;
  var ds = variables.dynState;
  var boost = ds ? ds.boost : 0;
  var names = { 1: "тихо", 2: "медленно", 3: "средне", 4: "быстро", 5: "турбо" };
  if (options.logEnabled) console.info("[Кондиционер] [DEBUG] [" + (options.room || "-") + "]" +
    " Т=" + temp + "°C" +
    " пороги=[" + t1 + "," + t2 + "," + t3 + "," + t4 + "]" +
    " база=" + (names[baseSpeed] || baseSpeed) +
    " boost=" + boost +
    " итог=" + (names[finalSpeed] || finalSpeed) +
    (isNight ? " (ночь)" : " (день)"));
}

function calcSpeed(temp, options, isNight) {
  var t1 = isNight ? options.speedTemp1Night : options.speedTemp1;
  var t2 = isNight ? options.speedTemp2Night : options.speedTemp2;
  var t3 = isNight ? options.speedTemp3Night : options.speedTemp3;
  var t4 = isNight ? options.speedTemp4Night : options.speedTemp4;

  if (temp < t1) return 1;
  if (temp < t2) return 2;
  if (temp < t3) return 3;
  if (temp < t4) return 4;
  return 5;
}

// ═══════════════════════════════════════════════════════════════════════════
// ДИНАМИКА СКОРОСТИ
//
// Логика:
//   finalSpeed = min(baseSpeed + boost, 5)
//
//   boost растёт (+1) если температура не снижается N минут.
//   boost сбрасывается до 0 если температура опустилась ниже:
//     - нижней границы текущего baseSpeed (т.е. calcSpeed вернул меньше).
//
//   Таким образом:
//     — при снижении температуры baseSpeed уменьшается сам (пересчёт по temp),
//       boost сбрасывается → finalSpeed сразу падает.
//     — при стагнации → boost накапливается.
// ═══════════════════════════════════════════════════════════════════════════
function applyDynamic(baseSpeed, temp, type, variables, options) {
  if (!options.dynamicEnabled) return baseSpeed;

  var now = Date.now();
  var tN  = (options.dynamicMinutes || 15) * 60 * 1000;
  var speedDelay = (options.speedDownDelay && options.speedDownDelay > 0) ? options.speedDownDelay : 2;
  var ds  = variables.dynState;

  // Инициализация или смена режима
  if (!ds || ds.type !== type) {
    variables.dynState = {
      type: type,
      boost: 0,
      baseSpeedAtBoost: baseSpeed, // скорость в момент накопления boost
      minTemp: temp,
      ts: now,
      pendingSpeed: 0,
      pendingCount: 0
    };
    return baseSpeed;
  }

  // Гарантируем что baseSpeedAtBoost всегда число
  if (typeof ds.baseSpeedAtBoost !== "number") ds.baseSpeedAtBoost = baseSpeed;

  var finalSpeed = Math.min(baseSpeed + ds.boost, 5);

  // ── Снижение: только если температура опустилась НИЖЕ зоны где накапливался boost
  // baseSpeed < baseSpeedAtBoost означает что calcSpeed вернул меньше чем было
  // при накоплении boost — т.е. температура реально ушла в другую ступень вниз.
  // Если boost=0 — сравниваем baseSpeed с baseSpeedAtBoost (они равны при старте).
  if (baseSpeed < ds.baseSpeedAtBoost) {
    if (ds.pendingSpeed === baseSpeed) {
      ds.pendingCount += 1;
    } else {
      ds.pendingSpeed = baseSpeed;
      ds.pendingCount = 1;
    }

    if (ds.pendingCount >= speedDelay) {
      var oldFinal = finalSpeed;
      var newFinal = baseSpeed;
      if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || type) + "] Снижение скорости: Т=" + temp +
        "°C → " + oldFinal + "→" + newFinal + " (подтверждено " + ds.pendingCount + "/" + speedDelay + " цикла)");
      ds.boost = 0;
      ds.baseSpeedAtBoost = baseSpeed;
      ds.minTemp = temp;
      ds.ts = now;
      ds.pendingSpeed = 0;
      ds.pendingCount = 0;
      return newFinal;
    }
    // Ещё не подтверждено — держим текущую скорость
    return finalSpeed;
  }

  // Если baseSpeed вырос или равен baseSpeedAtBoost — сбрасываем pending
  if (baseSpeed >= ds.baseSpeedAtBoost) {
    ds.pendingSpeed = 0;
    ds.pendingCount = 0;
    // Если baseSpeed вырос (температура поднялась в более высокую ступень) —
    // обновляем baseSpeedAtBoost и сбрасываем boost (он уже не нужен)
    if (baseSpeed > ds.baseSpeedAtBoost) {
      ds.boost = 0;
      ds.baseSpeedAtBoost = baseSpeed;
    }
  }

  // ── Повышение boost: температура не снижается N минут ───────────────────
  if (temp >= ds.minTemp && (now - ds.ts) >= tN && (baseSpeed + ds.boost) < 5) {
    ds.boost += 1;
    ds.baseSpeedAtBoost = baseSpeed; // фиксируем зону накопления
    ds.ts = now;
    var newF = Math.min(baseSpeed + ds.boost, 5);
    if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || type) + "] Динамика +1: Т=" + temp +
      "°C не снижалась " + (options.dynamicMinutes || 15) + " мин → скорость →" + newF);
  }

  // Температура снизилась — обновляем минимум и перезапускаем таймер стагнации
  if (temp < ds.minTemp) {
    ds.minTemp = temp;
    ds.ts = now;
  }

  return Math.min(baseSpeed + ds.boost, 5);
}

// ═══════════════════════════════════════════════════════════════════════════
// ПРИМЕНИТЬ НАСТРОЙКИ К КОНДИЦИОНЕРУ
// ═══════════════════════════════════════════════════════════════════════════
function applyAC(options, mode, targetTemp, speed, variables) {
  var svc = getService(options.acService);
  if (!svc) { console.warn("[Кондиционер] acService не задан"); return; }

  var last = variables ? variables.lastState : undefined;
  var changed = !last ||
    last.mode  !== mode  ||
    last.temp  !== targetTemp ||
    last.speed !== speed;

  if (changed) {
    var names = { 1: "тихо", 2: "медленно", 3: "средне", 4: "быстро", 5: "турбо" };
    var prev  = last ? (last.mode === 0 ? "выкл" : (names[last.speed] || last.speed)) : "первый запуск";
    if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] ON →" +
      " целевая=" + targetTemp + "°C" +
      " скорость=" + (names[speed] || speed) +
      " T=" + (options._lastTemp !== undefined ? options._lastTemp + "°C" : "?") +
      " | было: " + prev);
    if (variables) variables.lastState = { mode: mode, temp: targetTemp, speed: speed };
  }

  try {
    // Number() защищает от передачи undefined в setValue — Nashorn бросает
    // "Undefined cannot be cast to class vy" если значение не является числом
    svc.getCharacteristic(HC.TargetHeatingCoolingState).setValue(Number(mode) || 0);
    svc.getCharacteristic(HC.TargetTemperature).setValue(Number(targetTemp) || 24);
    svc.getCharacteristic(HC.C_FanSpeed).setValue(Number(speed) || 1);
  } catch(e) {
    console.error("[Кондиционер] applyAC: " + e.message + (e.lineNumber ? " (line " + e.lineNumber + ")" : ""));
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ВЫКЛЮЧИТЬ КОНДИЦИОНЕР
// ═══════════════════════════════════════════════════════════════════════════
function turnOffAC(options, variables, reason) {
  var svc = getService(options.acService);
  if (!svc) return;

  var last = variables ? variables.lastState : undefined;
  if (last && last.mode === 0) return; // уже выключен

  var tStr = (options._lastTemp !== undefined) ? " (Т=" + options._lastTemp + "°C)" : "";
  if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Выключение" + tStr + ". Причина: " + reason);
  if (variables) {
    variables.lastState = { mode: 0, temp: 0, speed: 0 };
    variables.dynState  = undefined; // сбрасываем динамику при выключении
  }

  try {
    svc.getCharacteristic(HC.TargetHeatingCoolingState).setValue(0);
  } catch(e) {
    console.error("[Кондиционер] turnOffAC: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ДИСПЛЕЙ (Switch, HC.On) — лог только при изменении
// ═══════════════════════════════════════════════════════════════════════════
function updateDisplay(isNight, options, variables) {
  if (!options.displayService || options.displayService === "") return;
  try {
    var svc = getService(options.displayService);
    if (!svc) return;
    var displayOn = !isNight;
    var last = variables ? variables.lastDisplayState : undefined;
    if (last !== displayOn) {
      if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Дисплей → " + (displayOn ? "ВКЛ (день)" : "ВЫКЛ (ночь)"));
      if (variables) variables.lastDisplayState = displayOn;
    }
    svc.getCharacteristic(HC.On).setValue(displayOn);
  } catch(e) {
    console.error("[Кондиционер] updateDisplay: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ПРОВЕРКА ОКОН — лог только при изменении состояния
// ═══════════════════════════════════════════════════════════════════════════
function checkWindowOpen(options, room, variables) {
  var sensors = [
    options.windowSensor1, options.windowSensor2,
    options.windowSensor3, options.windowSensor4
  ].filter(function(s) { return s && s !== ""; });

  if (sensors.length === 0) return false;

  var openSensor = null;
  for (var i = 0; i < sensors.length; i++) {
    try {
      var svc = getService(sensors[i]);
      if (!svc) continue;
      var val = svc.getCharacteristic(HC.ContactSensorState).getValue();
      if (val === 1) { openSensor = sensors[i]; break; }
    } catch(e) { /* игнорируем */ }
  }

  var isOpen = (openSensor !== null);

  // Логируем только при изменении
  var lastOpen = variables ? variables.lastWindowOpen : undefined;
  if (lastOpen !== isOpen) {
    if (isOpen) {
      if (options.logEnabled) console.info("[Кондиционер] [" + room + "] Окно открыто — кондиционер выключается");
    } else {
      if (options.logEnabled) console.info("[Кондиционер] [" + room + "] Окно закрыто — кондиционер может работать");
    }
    if (variables) variables.lastWindowOpen = isOpen;
  }

  return isOpen;
}

// ═══════════════════════════════════════════════════════════════════════════
// ОСТАЛЬНЫЕ ПРОВЕРКИ
// ═══════════════════════════════════════════════════════════════════════════
function isWinterMode(options) {
  if (!options.winterSummerSwitch || options.winterSummerSwitch === "") return false;
  try {
    var svc = getService(options.winterSummerSwitch);
    if (!svc) return false;
    return svc.getCharacteristic(HC.On).getValue() === true;
  } catch(e) { return false; }
}

function isOutdoorTempOk(options) {
  if (!options.outdoorTempService || options.outdoorTempService === "") return true;
  var temp = readSensor(options.outdoorTempService, HC.CurrentTemperature);
  if (temp === null) return true;
  return temp >= options.outdoorTempMin;
}

function isPersonAtHome(options) {
  var sensors = [
    options.occupancyPerson1Service,
    options.occupancyPerson2Service,
    options.occupancyPerson3Service
  ].filter(function(s) { return s && s !== ""; });
  if (sensors.length === 0) return true;
  for (var i = 0; i < sensors.length; i++) {
    if (readOccupancy(sensors[i]) === 1) return true;
  }
  return false;
}

function isPersonInRoom(options) {
  if (!options.occupancyRoomService || options.occupancyRoomService === "") return true;
  return readOccupancy(options.occupancyRoomService) === 1;
}

// ═══════════════════════════════════════════════════════════════════════════
// ОТЛОЖЕННОЕ ВЫКЛЮЧЕНИЕ
// ═══════════════════════════════════════════════════════════════════════════
function scheduleOff(variables, options, reason) {
  if (variables.offTimer) return;
  var delay = (options.offDelayMinutes && options.offDelayMinutes > 0) ? options.offDelayMinutes : 1;
  var delayMs = delay * 60 * 1000;
  if (options.logEnabled) console.info("[Кондиционер] [" + (options.room || "-") + "] Таймер выключения через " +
    delay + " мин. Причина: " + reason);
  variables.offTimer = setTimeout(function() {
    variables.offTimer = undefined;
    turnOffAC(options, variables, reason + " (таймер)");
  }, delayMs);
}

function cancelOffTimer(variables) {
  if (variables.offTimer) {
    clearTimeout(variables.offTimer);
    variables.offTimer = undefined;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ВСПОМОГАТЕЛЬНАЯ: логировать только при изменении значения
// ═══════════════════════════════════════════════════════════════════════════
function logOnChange(variables, key, value, message, options) {
  if (!variables) return false;
  var changed = (variables[key] !== value);
  var _o = (options && typeof options === "object") ? options : {};
  if (changed && message && _o.logEnabled) console.info("[Кондиционер] " + message);
  variables[key] = value;
  return changed;
}

// ═══════════════════════════════════════════════════════════════════════════
// ЧТЕНИЕ ДАТЧИКОВ
// ═══════════════════════════════════════════════════════════════════════════
function readSensor(serviceUUID, charType) {
  if (!serviceUUID || serviceUUID === "") return null;
  try {
    var svc = getService(serviceUUID);
    if (!svc) return null;
    var acc = svc.getAccessory();
    var infoSvc = null;
    acc.getServices().forEach(function(s) {
      if (s.getType() === HS.AccessoryInformation) infoSvc = s;
    });
    if (infoSvc) {
      var online = infoSvc.getCharacteristic(HC.C_Online);
      if (online && online.getValue() !== true) {
        console.warn("[Кондиционер] Датчик offline: " + serviceUUID);
        return null;
      }
    }
    var val = svc.getCharacteristic(charType);
    return (val !== null && val !== undefined) ? val.getValue() : null;
  } catch(e) {
    console.warn("[Кондиционер] readSensor(" + serviceUUID + "): " + e.message);
    return null;
  }
}

function readOccupancy(serviceUUID) {
  var val = readSensor(serviceUUID, HC.OccupancyDetected);
  return (val !== null && val !== undefined) ? Number(val) : 0;
}

// ═══════════════════════════════════════════════════════════════════════════
// БАЗОВЫЕ УТИЛИТЫ
// ═══════════════════════════════════════════════════════════════════════════
function getService(uuid) {
  if (!uuid || uuid === "") return null;
  try {
    var parts = uuid.split(".");
    return Hub.getAccessory(parts[0]).getService(parts[1]);
  } catch(e) {
    console.warn("[Кондиционер] getService(" + uuid + "): " + e.message);
    return null;
  }
}

function getACState(options) {
  try {
    var svc = getService(options.acService);
    if (!svc) return 0;
    var val = svc.getCharacteristic(HC.CurrentHeatingCoolingState);
    return val ? val.getValue() : 0;
  } catch(e) { return 0; }
}

function getSecurityState(serviceUUID) {
  if (!serviceUUID || serviceUUID === "") return 0;
  try {
    var svc = getService(serviceUUID);
    if (!svc) return 0;
    return svc.getCharacteristic(HC.SecuritySystemCurrentState).getValue();
  } catch(e) {
    console.warn("[Кондиционер] getSecurityState: " + e.message);
    return 0;
  }
}

function isNightTime(options) {
  var now   = new Date();
  var cur   = now.getHours() * 60 + now.getMinutes();
  var tS    = parseTime(options.nightStart);
  var tE    = parseTime(options.nightEnd);
  var start = tS.h * 60 + tS.m;
  var end   = tE.h * 60 + tE.m;
  return (start > end) ? (cur >= start || cur < end) : (cur >= start && cur < end);
}

function parseTime(str) {
  var parts = (str || "00:00").match(/^(\d{1,2}):(\d{2})$/);
  if (!parts) return { h: 0, m: 0 };
  return { h: parseInt(parts[1], 10), m: parseInt(parts[2], 10) };
}

function getServiceList(serviceTypes, charType) {
  var result   = [{ name: { ru: "Не выбрано", en: "Not selected" }, value: "" }];
  var unsorted = [];
  Hub.getAccessories().forEach(function(acc) {
    acc.getServices().filter(function(svc) {
      return serviceTypes.indexOf(svc.getType()) >= 0;
    }).forEach(function(svc) {
      var c = svc.getCharacteristic(charType);
      if (c) {
        var accName  = acc.getName();
        var svcName  = svc.getName();
        var roomName = acc.getRoom() ? acc.getRoom().getName() : "";
        var label    = roomName + " → " + (accName === svcName ? accName : accName + " " + svcName) + " (" + svc.getUUID() + ")";
        unsorted.push({ name: { ru: label, en: label }, value: svc.getUUID() });
      }
    });
  });
  unsorted.sort(function(a, b) { return a.name.ru.localeCompare(b.name.ru); });
  unsorted.forEach(function(s) { result.push(s); });
  return result;
}
